from pydantic import BaseModel, Field, validator
from typing import List
from langchain_core.output_parsers import PydanticOutputParser

class Invoice(BaseModel):
    invoice_number: str = Field(..., pattern=r'^INV-\d{6}')
    date: str = Field(..., regex=r'^\d{4}-\d{2}-\d{2}')
    total: float = Field(..., gt=0)
    line_items: List[dict] = Field(..., min_items=1)

    @validator('total')
    def total_must_be_positive(cls, v):
        if v <= 0:
            raise ValueError('Total must be positive')
        return v

parser = PydanticOutputParser(pydantic_object=Invoice)
prompt = parser.get_format_instructions()

# Usage in LangGraph node:
def extract_invoice(state):
    llm_chain = llm.with_structured_output(Invoice)
    result = llm_chain.invoke(state['document'])
    return {'extraction': result.dict()}

