import vex

from langgraph.graph import StateGraph

@vex.node(
    name="validate_merge",
    spec={
        "asserts": [
            {"type": "field_consistency", "fields": ["entities.name", "amounts.entity"]},
            {"type": "type_consistency", "schema": Invoice.model_json_schema()},
            {"type": "completeness", "min_fields": 3}
        ]
    }
)
def validate_extraction_merge(state):
    merged = {
        **state.get('entities', {}),
        **state.get('dates', {}),
        **state.get('amounts', {})
    }

    # Vex automatically validates and returns verdict
    return {
        'merged_extraction': merged,
        'validation_passed': True
    }

# Add to graph
graph.add_node("validate", validate_extraction_merge)
graph.add_edge("amounts", "validate")

import vex

@vex.node(
    name="human_review",
    spec={
        "asserts": [
            {"type": "critical_field_present", "fields": ["total", "invoice_number"]},
            {"type": "confidence_below_threshold", "max_confidence": 0.95}
        ],
        "enforce_breakpoint": True
    },
    timeout=3600  # 1 hour for human review
)
def human_review_node(state):
    extraction = state['extraction']

    print(f"🚨 HUMAN REVIEW NEEDED: {extraction}")
    print("Waiting for approval...")

    # Simulate human approval
    approved = input("Approve? (y/n): ") == 'y'

    if approved:
        return {'extraction': extraction, 'approved': True}
    else:
        raise ValueError("Human rejected extraction")

# Add to graph with Vex enforcement
graph.add_node("human_review", human_review_node)
graph.add_conditional_edges("validate", 
    lambda x: "human_review" if x.get('confidence', 0) < 0.95 else END,
    {"human_review": "human_review", "approved": END}
)
